unsigned long long run_event_based_simulation(Input in, SimulationData SD, double * sim_runtime)
{
	double start = get_time();

	int * verification_array_host = (int *) malloc( in.lookups * sizeof(int));

  OpenCLInfo CL = initialize_device(in.platform_id, in.device_id);
  cl_device_id device_id = CL.device_id;
  cl_context context = CL.context;
  cl_command_queue command_queue = CL.command_queue;

  printf("Initializing OpenCL data structures and JIT compiling kernel...\n");

  size_t sz = SD.length_num_nucs * sizeof(int);
  cl_int ret;
  cl_mem num_nucs_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, num_nucs_d, CL_TRUE, 0, sz, SD.num_nucs, 0, NULL, NULL);
  check(ret);

  sz = SD.length_concs * sizeof(double);
  cl_mem concs_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, concs_d, CL_TRUE, 0, sz, SD.concs, 0, NULL, NULL);
  check(ret);

  sz = SD.length_mats * sizeof(int);
  cl_mem mats_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, mats_d, CL_TRUE, 0, sz, SD.mats, 0, NULL, NULL);
  check(ret);

  sz = in.lookups * sizeof(int);
  cl_mem verification_array = clCreateBuffer(context, CL_MEM_READ_WRITE,  sz, NULL, &ret);
  check(ret);

  sz = SD.length_n_windows * sizeof(int);
  cl_mem n_windows_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, n_windows_d, CL_TRUE, 0, sz, SD.n_windows, 0, NULL, NULL);
  check(ret);

  sz = SD.length_poles * sizeof(Pole);
  cl_mem poles_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, poles_d, CL_TRUE, 0, sz, SD.poles, 0, NULL, NULL);
  check(ret);

  sz = SD.length_windows * sizeof(Window);
  cl_mem windows_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, windows_d, CL_TRUE, 0, sz, SD.windows, 0, NULL, NULL);
  check(ret);

  sz = SD.length_pseudo_K0RS * sizeof(double);
  cl_mem pseudo_K0RS_d = clCreateBuffer(context, CL_MEM_READ_ONLY,  sz, NULL, &ret);
  check(ret);
  ret = clEnqueueWriteBuffer(command_queue, pseudo_K0RS_d, CL_TRUE, 0, sz, SD.pseudo_K0RS, 0, NULL, NULL);
  check(ret);

  cl_program program = clCreateProgramWithSource(context, 1, (const char **)&kernel_source, NULL, &ret);
  check(ret);

  ret = clBuildProgram(program, 1, &device_id, NULL, NULL, NULL);
  check(ret);

  printCompilerError( program, device_id );

  cl_kernel kernel = clCreateKernel(program, "macro_xs_lookup_kernel", &ret);
  check(ret);

  ret = clSetKernelArg(kernel, 0, sizeof(Input), (void *)&in);
  check(ret);
  ret = clSetKernelArg(kernel, 1, sizeof(cl_mem), (void *)&num_nucs_d);
  check(ret);
  ret = clSetKernelArg(kernel, 2, sizeof(cl_mem), (void *)&mats_d);
  check(ret);
  ret = clSetKernelArg(kernel, 3, sizeof(int), (void *)&SD.max_num_nucs);
  check(ret);
  ret = clSetKernelArg(kernel, 4, sizeof(cl_mem), (void *)&concs_d);
  check(ret);
  ret = clSetKernelArg(kernel, 5, sizeof(cl_mem), (void *)&n_windows_d);
  check(ret);
  ret = clSetKernelArg(kernel, 6, sizeof(cl_mem), (void *)&pseudo_K0RS_d);
  check(ret);
  ret = clSetKernelArg(kernel, 7, sizeof(cl_mem), (void *)&windows_d);
  check(ret);
  ret = clSetKernelArg(kernel, 8, sizeof(cl_mem), (void *)&poles_d);
  check(ret);
  ret = clSetKernelArg(kernel, 9, sizeof(int), (void *)&SD.max_num_windows);
  check(ret);
  ret = clSetKernelArg(kernel, 10, sizeof(int), (void *)&SD.max_num_poles);
  check(ret);
  ret = clSetKernelArg(kernel, 11, sizeof(cl_mem), (void *)&verification_array);
  check(ret);

  double stop = get_time();
  printf("OpenCL initialization time: %.3lf seconds\n", stop-start);
  start = stop;

  border_print();
	center_print("SIMULATION", 79);
	border_print();

  printf("Running event based simulation...\n");

	size_t global_item_size = in.lookups; 
	size_t local_item_size = 256; 

  if( in.lookups % local_item_size != 0 && in.lookups > local_item_size )
    global_item_size = ((in.lookups / local_item_size) + 1) * local_item_size;

  ret = clEnqueueNDRangeKernel(command_queue, kernel, 1, NULL, &global_item_size, &local_item_size, 0, NULL, NULL);
  check(ret);

  ret = clEnqueueReadBuffer(command_queue, verification_array, CL_TRUE, 0, in.lookups * sizeof(int), verification_array_host, 0, NULL, NULL);
  check(ret);

  printf("Reducing verification value...\n");

  unsigned long long verification = 0;

  for( int l = 0; l < in.lookups; l++ )
    verification += verification_array_host[l];

  stop = get_time();
  *sim_runtime = stop-start;
  printf("Simulation + Verification Reduction Runtime: %.3lf seconds\n", *sim_runtime);

  ret = clFlush(command_queue);
  check(ret);
  ret = clFinish(command_queue);
  check(ret);
  ret = clReleaseKernel(kernel);
  check(ret);
  ret = clReleaseProgram(program);
  check(ret);
  ret = clReleaseMemObject(num_nucs_d);
  check(ret);
  ret = clReleaseMemObject(mats_d);
  check(ret);
  ret = clReleaseMemObject(n_windows_d);
  check(ret);
  ret = clReleaseMemObject(poles_d);
  check(ret);
  ret = clReleaseMemObject(windows_d);
  check(ret);
  ret = clReleaseMemObject(pseudo_K0RS_d);
  check(ret);
  ret = clReleaseMemObject(verification_array);
  check(ret);
  ret = clReleaseCommandQueue(command_queue);
  check(ret);
  ret = clReleaseContext(context);
  check(ret);

  free(verification_array_host);

  return verification;
}

double LCG_random_double(uint64_t * seed)
{
  const uint64_t m = 9223372036854775808ULL; 
  const uint64_t a = 2806196910506780709ULL;
  const uint64_t c = 1ULL;
  *seed = (a * (*seed) + c) % m;
  return (double) (*seed) / (double) m;
}	

uint64_t LCG_random_int(uint64_t * seed)
{
  const uint64_t m = 9223372036854775808ULL; 
  const uint64_t a = 2806196910506780709ULL;
  const uint64_t c = 1ULL;
  *seed = (a * (*seed) + c) % m;
  return *seed;
}	

RSComplex c_mul( RSComplex A, RSComplex B)
{
  double a = A.r;
  double b = A.i;
  double c = B.r;
  double d = B.i;
  RSComplex C;
  C.r = (a*c) - (b*d);
  C.i = (a*d) + (b*c);
  return C;
}

SimulationData initialize_simulation( Input input )
{
	uint64_t seed = INITIALIZATION_SEED;

	printf("Loading Hoogenboom-Martin material data...\n");
	SimulationData SD = get_materials( input, &seed ); 

	printf("Generating resonance distributions...\n");
	SD.n_poles = generate_n_poles( input, &seed );
	SD.length_n_poles = input.n_nuclides;

	printf("Generating window distributions...\n");
	SD.n_windows = generate_n_windows( input, &seed );
	SD.length_n_windows = input.n_nuclides;

	printf("Generating resonance parameter grid...\n");
	SD.poles = generate_poles( input, SD.n_poles, &seed, &SD.max_num_poles );
	SD.length_poles = input.n_nuclides * SD.max_num_poles;

	printf("Generating window parameter grid...\n");
	SD.windows = generate_window_params( input, SD.n_windows, SD.n_poles, &seed, &SD.max_num_windows);
	SD.length_windows = input.n_nuclides * SD.max_num_windows;

	printf("Generating 0K l_value data...\n");
	SD.pseudo_K0RS = generate_pseudo_K0RS( input, &seed );
	SD.length_pseudo_K0RS = input.n_nuclides * input.numL;

	return SD;
}

int * generate_n_poles( Input input, uint64_t * seed )
{
	int total_resonances = input.avg_n_poles * input.n_nuclides;

	int * R = (int *) malloc( input.n_nuclides * sizeof(int));

	for( int i = 0; i < input.n_nuclides; i++ )
		R[i] = 1;

	for( int i = 0; i < total_resonances - input.n_nuclides; i++ )
		R[LCG_random_int(seed) % input.n_nuclides]++;

	return R;
}

int * generate_n_windows( Input input, uint64_t * seed )
{
	int total_resonances = input.avg_n_windows * input.n_nuclides;

	int * R = (int *) malloc( input.n_nuclides * sizeof(int));

	for( int i = 0; i < input.n_nuclides; i++ )
		R[i] = 1;

	for( int i = 0; i < total_resonances - input.n_nuclides; i++ )
		R[LCG_random_int(seed) % input.n_nuclides]++;

	return R;
}

Pole * generate_poles( Input input, int * n_poles, uint64_t * seed, int * max_num_poles )
{
	double f = 152.5;
	RSComplex f_c = {f, 0};

	int max_poles = -1;

	for( int i = 0; i < input.n_nuclides; i++ )
	{
		if( n_poles[i] > max_poles)
			max_poles = n_poles[i];
	}
	*max_num_poles = max_poles;

	Pole * R = (Pole *) malloc( input.n_nuclides * max_poles * sizeof(Pole));

	for( int i = 0; i < input.n_nuclides; i++ )
		for( int j = 0; j < n_poles[i]; j++ )
		{
			double r = LCG_random_double(seed);
			double im = LCG_random_double(seed);
			RSComplex t1 = {r, im};
			R[i * max_poles + j].MP_EA = c_mul(f_c,t1);
			r = LCG_random_double(seed);
			im = LCG_random_double(seed);
			RSComplex t2 = {f*r, im};
			R[i * max_poles + j].MP_RT = t2;
			r = LCG_random_double(seed);
			im = LCG_random_double(seed);
			RSComplex t3 = {f*r, im};
			R[i * max_poles + j].MP_RA = t3;
			r = LCG_random_double(seed);
			im = LCG_random_double(seed);
			RSComplex t4 = {f*r, im};
			R[i * max_poles + j].MP_RF = t4;
			R[i * max_poles + j].l_value = LCG_random_int(seed) % input.numL;
		}

	return R;
}

Window * generate_window_params( Input input, int * n_windows, int * n_poles, uint64_t * seed, int * max_num_windows )
{
	int max_windows = -1;

	for( int i = 0; i < input.n_nuclides; i++ )
	{
		if( n_windows[i] > max_windows)
			max_windows = n_windows[i];
	}
	*max_num_windows = max_windows;

	Window * R = (Window *) malloc( input.n_nuclides * max_windows * sizeof(Window));

	for( int i = 0; i < input.n_nuclides; i++ )
	{
		int space = n_poles[i] / n_windows[i];
		int remainder = n_poles[i] - space * n_windows[i];
		int ctr = 0;
		for( int j = 0; j < n_windows[i]; j++ )
		{
			R[i * max_windows + j].T = LCG_random_double(seed);
			R[i * max_windows + j].A = LCG_random_double(seed);
			R[i * max_windows + j].F = LCG_random_double(seed);
			R[i * max_windows + j].start = ctr; 
			R[i * max_windows + j].end = ctr + space - 1;

			ctr += space;

			if ( j < remainder )
			{
				ctr++;
				R[i * max_windows + j].end++;
			}
		}
	}

	return R;
}

double * generate_pseudo_K0RS( Input input, uint64_t * seed )
{
	double * R = (double *) malloc( input.n_nuclides * input.numL * sizeof(double));

	for( int i = 0; i < input.n_nuclides; i++)
		for( int j = 0; j < input.numL; j++ )
			R[i * input.numL + j] = LCG_random_double(seed);

	return R;
}

